const q=s=>document.querySelector(s), toast=t=>{q('#toast').textContent=t;q('#toast').classList.add('show');setTimeout(()=>q('#toast').classList.remove('show'),1600)};
function shell(){const unlocked=window.BusinessBackend?.hasProtection();q('#sideNav').innerHTML=side.map(([i,n,p])=>`<button class="navitem ${p===current?'active':''} ${p>0&&!unlocked?'locked':''}" data-page="${p}"><span class="ico">${i}</span>${n}${p>0&&!unlocked?'<small>🔒</small>':''}</button>`).join('');q('#steps').innerHTML=pages.map((p,i)=>`<div class="step ${i===current?'active':''} ${i>0&&!unlocked?'locked':''}" data-page="${i}"><b>${i+1}</b>${p.name}</div>`).join('');document.querySelectorAll('[data-page]').forEach(x=>x.onclick=()=>{let p=+x.dataset.page;if(p>0&&!window.BusinessBackend?.hasProtection()){toast('请先保存或选择已配置的活动防护范围');return}if(p>=0){current=p;location.hash=p+1;render()}})}
function tools(){return `<div class="map-tools"><button>▱</button><button>⌁</button><button>＋</button><button>−</button><button>↶</button></div>`}
function map(i,dark=false){return `<div class="map ${dark?'dark':''}" style="background-image:url('${pages[i].img}');background-size:1920px 1080px;background-position:${i===0?'-265px -146px':i===1?'-498px -124px':i===2?'-594px -140px':i===4?'-252px -253px':'-570px -132px'}">${tools()}<div class="ring r2"></div><div class="ring r1"></div><div class="pin">奥体中心体育场</div><div class="legend"><b>图层控制</b><br>🟦 二级防护区<br>🟥 一级防护区<br>🟢 设备点位</div></div>`}
map=function(i,dark=false){return `<div class="map real-map ${dark&&i!==4?'dark':''}" data-page="${i}"><div class="map-canvas" id="map-${i}"></div><div class="map-tools"><button data-map-action="style" title="切换卫星影像" aria-label="切换卫星影像"><i class="ti ti-satellite"></i></button><button data-map-action="pitch" title="切换二三维视图" aria-label="切换二三维视图"><i class="ti ti-building-skyscraper"></i></button><button data-map-action="in" title="放大地图" aria-label="放大地图"><i class="ti ti-plus"></i></button><button data-map-action="out" title="缩小地图" aria-label="缩小地图"><i class="ti ti-minus"></i></button><button data-map-action="home" title="返回活动中心" aria-label="返回活动中心"><i class="ti ti-current-location"></i></button></div><div class="legend"><b>地图图层</b><label><input type="checkbox" data-layer="zones" checked> 防护区域</label><label><input type="checkbox" data-layer="points" checked> 设备/目标</label>${i<=2||i===4?'':`<label><input type="checkbox" data-layer="routes" checked> 路线/轨迹</label>`}</div><div class="map-loading">正在加载真实地图…</div></div>`}
const rows=(n=6)=>Array.from({length:n},(_,i)=>`<tr><td>${i+1}</td><td><a>WL20240920000${i+1}</a></td><td>${i%3?'多旋翼无人机':'垂直起降固定翼'}</td><td>杭州市公安局</td><td>${['张伟','李强','王磊'][i%3]}</td><td>一级防护区</td><td><span class="status ${i%4===2?'warn':'ok'}">${i%4===2?'审核中':'已通过'}</span></td><td><a>查看　详情</a></td></tr>`).join('');
function page1(){return `<div class="layout l1">${map(0)}<div class="panel right"><div class="panel-title">活动与防护配置</div><div class="detail"><dl><dt>活动名称</dt><dd><input value="杭州亚运会开幕式"></dd><dt>活动地点</dt><dd>杭州市奥体中心体育场</dd><dt>活动时间</dt><dd>2024-09-23 18:00 至 23:00</dd><dt>防护状态</dt><dd><span class="status ok">生效中</span></dd></dl><hr><h3>防护范围设置</h3><dl><dt>一级半径</dt><dd><input value="1000"> m</dd><dt>二级半径</dt><dd><input value="3000"> m</dd><dt>防护高度</dt><dd>0 m　至　120 m</dd></dl><p><button class="ghost action">取消</button>　<button class="primary action">保存并进入下一步</button></p></div></div><div class="panel bottom"><div class="panel-title">部署流程</div><div class="flow">${pages.map((p,i)=>`<span><b>${i+1}</b>${p.name}<br><small>${i?'待配置':'已完成'}</small></span>`).join('')}</div></div></div>`}
function page2(){return `<div class="layout l2"><div class="panel"><div class="panel-title">设备列表（5）</div><div class="list">${['雷达A01','光电E02','无线电侦测D03'].map((x,i)=>`<div class="list-item"><div class="row"><strong>${x}</strong><span class="ok">● 在线</span></div><span class="muted">覆盖半径　${i+2}000 m<br>安装高度　${28-i*4} m<br>工作状态　正常</span></div>`).join('')}<button class="ghost action">＋ 添加设备</button></div></div>${map(1)}<div class="panel"><div class="panel-title">覆盖评估结果</div><div class="cardgrid" style="grid-template-columns:1fr 1fr"><div class="metric">总体覆盖率<strong>92.6%</strong><small>较上次评估 ↑3.8%</small></div><div class="metric">盲区面积<strong>0.86</strong><small>km²</small></div><div class="metric">重叠覆盖率<strong>18.7%</strong></div><div class="metric">设备在线率<strong class="ok">100%</strong></div></div></div><div class="panel bottom"><div class="panel-title">评估结果列表 <button class="ghost action">导出评估报告</button></div><div class="table-wrap"><table><thead><tr><th>序号</th><th>设备名称</th><th>设备类型</th><th>安装位置</th><th>覆盖半径</th><th>影响区域</th><th>状态</th><th>优化建议</th></tr></thead><tbody>${rows(5)}</tbody></table></div></div></div>`}
