function page4(){return `<div class="layout l4"><div class="panel main"><div class="filters">活动名称<select><option>请选择活动</option></select> 所属单位<select><option>请选择</option></select> 审核状态<select><option>全部</option></select> 生效状态<select><option>全部</option></select><input placeholder="设备名称/序列号/飞手"><button class="primary action">新增设备</button><button class="ghost action">批量导入</button><button class="ghost action">批量审核</button></div><div class="table-wrap"><table><thead><tr><th>□</th><th>设备ID</th><th>设备类型</th><th>所属单位</th><th>飞手姓名</th><th>授权区域</th><th>审批状态</th><th>操作</th></tr></thead><tbody>${rows(8)}</tbody></table></div></div><div class="panel detailpanel"><div class="panel-title">设备详情　×</div><div class="detail"><div class="row"><strong>🚁　WL202409200001</strong><span class="status ok">生效中</span></div><p>设备类型：多旋翼无人机<br>品牌型号：DJI Mavic 3E<br>序列号：1581FSK8A22F00123</p><hr><h3>登记信息</h3><p>所属单位：杭州市公安局<br>飞手姓名：张伟<br>联系方式：138****1234<br>授权区域：一级防护区<br>飞行时段：08:00～18:00</p><hr><h3>审批材料</h3><p>▣ 飞行申请.pdf　<a>下载</a><br>▣ 飞手执照.pdf　<a>下载</a><br>▣ 设备合格证.pdf　<a>下载</a></p><hr><h3>审批流程</h3><p>🟣 提交申请<br>　│<br>🟣 单位初审<br>　│<br>🟢 平台审核</p></div></div><div class="panel bottom"><div class="panel-title">导入 / 操作记录</div><div class="table-wrap"><table><tbody>${rows(3)}</tbody></table></div></div></div>`}
function page5(){return `<div class="layout l5"><div class="metrics cardgrid" style="grid-template-columns:repeat(4,1fr);padding:0"><div class="metric">当前目标总数<strong>34</strong></div><div class="metric">白名单目标<strong>26</strong></div><div class="metric">异常目标<strong class="danger">8</strong></div><div class="metric">在线设备<strong>58 / 62</strong></div></div>${map(4,true)}<div class="panel side"><div class="panel-title">目标详情</div><div class="detail"><h2>🚁 T-20017　<span class="status danger">异常目标</span></h2><dl><dt>目标类型</dt><dd>多旋翼无人机</dd><dt>当前位置</dt><dd>30.241592°N, 120.155821°E</dd><dt>相对高度</dt><dd>260 m</dd><dt>飞行速度</dt><dd>35 m/s</dd><dt>航向</dt><dd>220°</dd><dt>所属区域</dt><dd><span class="status danger">一级防护区</span></dd></dl><button class="ghost action">立即处置</button></div><div class="panel-title">告警信息（未处置 5）</div><div class="list">${['高空异常目标闯入','异常目标接近核心区','频谱干扰告警','异常目标闯入','设备离线告警'].map((x,i)=>`<div class="list-item"><strong class="${i===2?'warn':'danger'}">⚠ ${x}</strong><br><span class="muted">14:${30-i}:21　T-2001${7-i}</span></div>`).join('')}</div></div><div class="panel timeline"><div class="panel-title">时间回放</div><div class="flow"><button class="primary action">▶</button><span>14:10 ━━━━━ 14:20 ━━━━━ <b>14:30</b> ━━━━━ 14:50</span><button class="ghost action">实时</button></div></div><div class="panel bottom"><div class="panel-title">轨迹回放记录</div><div class="table-wrap"><table><tbody>${rows(3)}</tbody></table></div></div></div>`}
function page6(){return `<div class="layout l6"><div class="panel alerts"><div class="panel-title">告警队列（18）</div><div class="filters"><select><option>全部等级</option></select><select><option>全部状态</option></select></div><div class="list">${['侵入防护圈告警','靠近防护圈告警','异常飞行告警','侵入防护圈告警','越界飞行告警'].map((x,i)=>`<div class="list-item"><div class="row"><strong><span class="status ${i%3===0?'danger':i%3===1?'warn':'info'}">${i%3===0?'高危':i%3===1?'中危':'低危'}</span> ${x}</strong><small>14:${28-i*2}:11</small></div><span class="muted">奥体中心体育场　东南侧<br>黑飞无人机｜高度 ${82+i*24}m｜速度 ${18-i}m/s</span></div>`).join('')}</div></div>${map(5)}<div class="panel d1"><div class="panel-title">告警详情</div><div class="detail"><dl><dt>告警等级</dt><dd><span class="status danger">高危</span></dd><dt>告警类型</dt><dd>侵入防护圈告警</dd><dt>告警编号</dt><dd>AL20240920142811</dd><dt>发生位置</dt><dd>奥体中心体育场 东南侧</dd><dt>发生时间</dt><dd>2024-09-20 14:28:11</dd><dt>目标类型</dt><dd>黑飞无人机</dd><dt>高度</dt><dd>82 m</dd><dt>速度</dt><dd>18 m/s</dd></dl></div></div><div class="panel d2"><div class="panel-title">推荐处置措施</div><div class="list">${['短信通知','电话通知','喊话器警示','现场处置','联动反制','关闭事件'].map(x=>`<div class="list-item action"><strong>▣　${x}</strong></div>`).join('')}</div></div><div class="panel bottom"><div class="panel-title">处置流程</div><div class="flow">${['发现告警','研判确认','下发指令','现场处置','闭环归档'].map((x,i)=>`<span><b>${i<4?'✓':'≡'}</b>${x}<br><small>${i<4?'14:2'+(8+i)+':11':'--:--:--'}</small></span>`).join('')}</div><div class="table-wrap"><table><tbody>${rows(5)}</tbody></table></div></div></div>`}
const ui={zoom:1,playing:false,timer:null,selected:null};
function openModal(title,body,onConfirm){q('#modalTitle').textContent=title;q('#modalBody').innerHTML=body;q('.modal-confirm').textContent='确认';q('#modal').classList.add('open');q('#modal').setAttribute('aria-hidden','false');q('.modal-confirm').onclick=()=>{const result=onConfirm?.();if(result!==false)closeModal()}}
function closeModal(){q('#modal').classList.remove('open','drawer-right');q('#modal').setAttribute('aria-hidden','true')}
function openRightDrawer(title,body){openModal(title,body,()=>toast('部署方案已应用'));q('#modal').classList.add('drawer-right');q('.modal-confirm').textContent='应用部署方案'}
function openMapDrawer(title,body){const map=q('.real-map');if(!map)return;map.querySelector('.map-side-drawer')?.remove();const drawer=document.createElement('aside');drawer.className='map-side-drawer';drawer.innerHTML=`<div class="panel-title">${title}<button aria-label="关闭">×</button></div><div class="drawer-body">${body}</div><div class="drawer-actions"><button class="ghost">取消</button><button class="primary">应用部署方案</button></div>`;map.appendChild(drawer);requestAnimationFrame(()=>drawer.classList.add('open'));drawer.querySelector('.panel-title button').onclick=drawer.querySelector('.drawer-actions .ghost').onclick=()=>drawer.remove();drawer.querySelector('.drawer-actions .primary').onclick=()=>{drawer.remove();toast('部署方案已应用，地图资源状态已同步')}}
function bindMap(){document.querySelectorAll('.map').forEach(m=>{const bs=getComputedStyle(m).backgroundSize.split(' ');const buttons=m.querySelectorAll('.map-tools button');buttons.forEach(b=>b.onclick=()=>{const t=b.textContent.trim();if(t==='＋'||t==='+')ui.zoom=Math.min(1.5,ui.zoom+.1);else if(t==='−'||t==='-')ui.zoom=Math.max(.8,ui.zoom-.1);else if(t==='↶')ui.zoom=1;else if(t==='▱'){m.classList.toggle('satellite');toast(m.classList.contains('satellite')?'已切换卫星底图':'已切换标准底图');return}else{m.classList.toggle('drawing');toast(m.classList.contains('drawing')?'标绘模式已开启':'标绘模式已关闭');return}m.style.backgroundSize=`${1920*ui.zoom}px ${1080*ui.zoom}px`;m.dataset.zoom=Math.round(ui.zoom*100)+'%';toast(`地图缩放 ${m.dataset.zoom}`)})})}
function bindTables(){document.querySelectorAll('tbody tr').forEach((tr,i)=>{tr.tabIndex=0;tr.onclick=e=>{if(e.target.closest('a,button,input'))return;document.querySelectorAll('tbody tr.selected').forEach(x=>x.classList.remove('selected'));tr.classList.add('selected');ui.selected=i;const id=tr.children[1]?.textContent?.trim();const detail=q('.detailpanel .detail');if(detail&&id){const title=detail.querySelector('strong');if(title)title.textContent='🚁　'+id;toast(`已选择 ${id}`)}};tr.onkeydown=e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();tr.click()}}});document.querySelectorAll('tbody a').forEach(a=>a.onclick=e=>{e.stopPropagation();openModal('记录详情',`<div class="detail"><p><b>${a.closest('tr')?.children[1]?.textContent||'当前记录'}</b></p><p>状态与关联信息已同步，您可以继续查看、编辑或导出该记录。</p></div>`,()=>toast('详情已确认'))})}
function bindFilters(){const box=q('.filters');if(!box)return;const input=box.querySelector('input');if(input)input.oninput=()=>{const key=input.value.trim().toLowerCase();q('#workspace').querySelectorAll('tbody tr').forEach(tr=>tr.classList.toggle('filtered',!!key&&!tr.textContent.toLowerCase().includes(key)))};box.querySelectorAll('select').forEach(sel=>sel.onchange=()=>{const value=sel.options[sel.selectedIndex].text;toast(`筛选条件：${value}`)});}
function bindLists(){if(current===4)return;document.querySelectorAll('.list .list-item').forEach((item,i)=>{item.tabIndex=0;item.onclick=e=>{if(e.target.closest('button,a'))return;item.parentElement.querySelectorAll('.list-item.active').forEach(x=>x.classList.remove('active'));item.classList.add('active');if(current===5){const level=item.querySelector('.status')?.textContent||'告警';const detail=q('.d1 .detail');if(detail){detail.dataset.alert=i;detail.querySelector('dd').innerHTML=`<span class="status ${i%3===0?'danger':i%3===1?'warn':'info'}">${level}</span>`}toast(`已载入第 ${i+1} 条告警`)}else toast('已切换当前项目')}})}
function bindPlayback(){if(current!==4)return;const buttons=q('.timeline')?.querySelectorAll('button');if(!buttons?.length)return;const play=buttons[0],live=buttons[1],label=q('.timeline .flow span');play.onclick=()=>{ui.playing=!ui.playing;play.textContent=ui.playing?'Ⅱ':'▶';if(ui.timer)clearInterval(ui.timer);if(ui.playing){let minute=30;ui.timer=setInterval(()=>{minute++;label.innerHTML=`14:10 ━━━━━ 14:20 ━━━━━ <b>14:${minute}</b> ━━━━━ 14:50`;if(minute>=50){clearInterval(ui.timer);ui.playing=false;play.textContent='▶'}},500)}toast(ui.playing?'开始轨迹回放':'回放已暂停')};live.onclick=()=>{if(ui.timer)clearInterval(ui.timer);ui.playing=false;play.textContent='▶';label.innerHTML='14:10 ━━━━━ 14:20 ━━━━━ <b>实时</b> ━━━━━ 14:50';toast('已返回实时态势')}}
function bindActions(){document.querySelectorAll('.action').forEach(b=>{if(b.closest('.timeline'))return;b.onclick=e=>{e.stopPropagation();const name=b.textContent.trim();if(current===5&&b.closest('.d2')){b.classList.toggle('done');toast(b.classList.contains('done')?`${name} 已执行`:`${name} 已取消`);return}openModal(name,`<p>确认执行“${name}”吗？操作结果会立即更新到当前页面。</p>`,()=>{b.classList.add('done');toast(`${name} 操作成功`)})}})}
function bindShell(){const collapse=q('.collapse'),syncCollapse=()=>{const mini=document.body.classList.contains('sidebar-mini');collapse.querySelector('.collapse-icon').textContent=mini?'›':'‹';collapse.querySelector('.collapse-label').textContent=mini?'展开导航':'收起导航';collapse.setAttribute('aria-label',mini?'展开导航':'折叠导航');collapse.title=mini?'展开导航':'折叠导航'};collapse.onclick=()=>{document.body.classList.toggle('sidebar-mini');localStorage.setItem('sidebarMini',document.body.classList.contains('sidebar-mini')?'1':'0');syncCollapse();activeMap&&setTimeout(()=>activeMap.resize(),220)};if(localStorage.getItem('sidebarMini')==='1')document.body.classList.add('sidebar-mini');syncCollapse();q('.modal-close').onclick=q('.modal-cancel').onclick=closeModal;q('#modal').onclick=e=>{if(e.target===q('#modal'))closeModal()};document.onkeydown=e=>{if(e.key==='Escape')closeModal()}}
