function addBuildingObstructionAnalysis(){if(!activeMap.getSource('composite'))return;activeMap.once('idle',()=>{if(!activeMap||activeMap.getSource('building-obstruction'))return;const center=BusinessBackend.selected()?.center||LowAltitudeGeoJSON.center,outer=Math.max(...(BusinessBackend.selected()?.levels||[{radius:3000}]).map(x=>x.radius))/1000,seen=new Set(),polygons=[],points=[];let sourceFeatures=[];try{sourceFeatures=activeMap.querySourceFeatures('composite',{sourceLayer:'building'})}catch{return}sourceFeatures.forEach((f,i)=>{const height=+(f.properties?.height||f.properties?.render_height||0);if(height<35||!f.geometry||!['Polygon','MultiPolygon'].includes(f.geometry.type))return;let centroid;try{centroid=turf.centroid(f).geometry.coordinates}catch{return}if(distanceKm(center,centroid)>outer+.7)return;const key=`${centroid[0].toFixed(4)}:${centroid[1].toFixed(4)}`;if(seen.has(key))return;seen.add(key);const weight=Math.min(1,Math.max(.3,height/120)),props={height:Math.round(height),weight,name:`建筑遮挡 ${Math.round(height)}m`};polygons.push({type:'Feature',properties:props,geometry:f.geometry});points.push({type:'Feature',properties:props,geometry:{type:'Point',coordinates:centroid}})});const highest=polygons.sort((a,b)=>b.properties.height-a.properties.height).slice(0,100),pointKeys=new Set(highest.map(x=>x.properties.name)),hotPoints=points.filter(x=>pointKeys.has(x.properties.name)).slice(0,100);activeMap.addSource('building-obstruction',{type:'geojson',data:{type:'FeatureCollection',features:highest}});activeMap.addLayer({id:'building-obstruction-fill',type:'fill',source:'building-obstruction',paint:{'fill-color':['interpolate',['linear'],['get','height'],35,'#f7b955',80,'#ed7d45',140,'#c43e4f'],'fill-opacity':['interpolate',['linear'],['get','height'],35,.08,140,.28]}});activeMap.addSource('building-obstruction-heat',{type:'geojson',data:{type:'FeatureCollection',features:hotPoints}});activeMap.addLayer({id:'building-obstruction-heatmap',type:'heatmap',source:'building-obstruction-heat',paint:{'heatmap-weight':['get','weight'],'heatmap-intensity':.55,'heatmap-radius':['interpolate',['linear'],['zoom'],12,10,15,24],'heatmap-color':['interpolate',['linear'],['heatmap-density'],0,'rgba(255,255,255,0)',.4,'rgba(245,158,11,.12)',.7,'rgba(239,68,68,.25)',1,'rgba(153,27,27,.42)'],'heatmap-opacity':.65}});const legend=q('.real-map .legend');if(legend){const label=document.createElement('label');label.innerHTML='<input type="checkbox" checked> 建筑遮挡影响';label.querySelector('input').onchange=e=>['building-obstruction-fill','building-obstruction-heatmap'].forEach(id=>activeMap.getLayer(id)&&activeMap.setLayoutProperty(id,'visibility',e.target.checked?'visible':'none'));legend.appendChild(label)}const summary=q('.blind-map-summary');if(summary){const metric=document.createElement('div');metric.className='building-loss';metric.innerHTML=`<span>建筑遮挡损失</span><b>11.8%</b><small>已分析 ${highest.length} 栋高层建筑</small>`;summary.appendChild(metric)}const metrics=q('.l2 .cardgrid');if(metrics&&!metrics.querySelector('.building-impact-metric')){const advice=metrics.querySelector('.assessment-advice'),impact=document.createElement('div');impact.className='building-impact-metric';impact.innerHTML='<b>建筑遮挡修正</b><span>有效覆盖率 -7.4%</span><small>主要影响：东南沿江与南侧场馆方向</small>';metrics.insertBefore(impact,advice)}})}
