function monitoringAlertRecords(){return LowAltitudeGeoJSON.alerts.features.map((feature,index)=>({feature,index,level:index<2?'高危':index===2?'中危':'低危',status:feature.properties.status||'待处置',time:`14:${String(28-index*2).padStart(2,'0')}:11`,code:`AL20261108${String(142811-index*200).padStart(6,'0')}`}))}

function droneRiskMeta(record){
  const level=record?.level||'';
  if(level==='高危')return{label:'高危',tone:'high'};
  if(level==='中危')return{label:'中危',tone:'medium'};
  if(level==='低危')return{label:'低危',tone:'low'};
  if(record?.type==='白名单无人机'||record?.feature?.properties?.kind?.includes('白名单'))return{label:'白名单',tone:'whitelist'};
  if(record?.feature?.properties?.kind?.includes('异常'))return{label:'高危',tone:'high'};
  return{label:'低危',tone:'low'};
}

function applyDronePointFilter(){
  if(!activeMap)return;
  const names=[...LowAltitudeGeoJSON.targets.features,...LowAltitudeGeoJSON.alerts.features].map(feature=>feature.properties.name);
  const filter=['!', ['in',['get','name'],['literal',names]]];
  ['points-halo','points-circle','points-label'].forEach(id=>{if(activeMap.getLayer(id))activeMap.setFilter(id,filter)});
}

function addDroneLabels(){
  if(!activeMap||![4,6].includes(current)||activeMap.getSource('drone-labels'))return;
  const features=monitoringTargetRecords().map(record=>{const risk=droneRiskMeta(record);return{type:'Feature',geometry:{type:'Point',coordinates:[...record.feature.geometry.coordinates]},properties:{name:record.feature.properties.name,risk:risk.label,tone:risk.tone}}});
  activeMap.addSource('drone-labels',{type:'geojson',data:{type:'FeatureCollection',features}});
  activeMap.addLayer({id:'drone-labels',type:'symbol',source:'drone-labels',layout:{'text-field':['get','name'],'text-size':10,'text-offset':[0,2.05],'text-anchor':'top','text-max-width':14,'text-allow-overlap':false,'text-ignore-placement':false},paint:{'text-color':'#ffffff','text-halo-color':'rgba(35,29,42,.9)','text-halo-width':2,'text-halo-blur':.4}});
}

function setupDroneRoleMarkers(){
  if(!activeMap||![4,6].includes(current))return;
  const add=(record,kind,index)=>{
    const risk=droneRiskMeta(record),anchor=document.createElement('div'),el=document.createElement('button');
    anchor.className='drone-marker-anchor';el.type='button';el.className=`drone-map-marker drone-${risk.tone}`;el.title=`${risk.label}｜${record.feature.properties.name}`;
    el.innerHTML='<i aria-hidden="true"></i>';anchor.appendChild(el);
    el.onclick=event=>{event.stopPropagation();if(current===4){kind==='alert'?showMonitoringAlert(index):showMonitoringTarget(index);return}activeMap.flyTo({center:record.feature.geometry.coordinates,zoom:14.5,duration:550});new mapboxgl.Popup({offset:22}).setLngLat(record.feature.geometry.coordinates).setHTML(`<b>${record.feature.properties.name}</b><br>${risk.label} · ${record.feature.properties.status||'持续监测'}`).addTo(activeMap)};
    new mapboxgl.Marker({element:anchor,anchor:'center'}).setLngLat(record.feature.geometry.coordinates).addTo(activeMap);
  };
  monitoringTargetRecords().filter(record=>record.alertIndex===null).forEach((record,index)=>add(record,'target',index));
  monitoringAlertRecords().forEach((record,index)=>add(record,'alert',index));
  applyDronePointFilter();addDroneLabels();
  activeMap.on('style.load',()=>setTimeout(()=>{applyDronePointFilter();addDroneLabels();addLeaderDroneHeat()},80));
}

function addLeaderDroneHeat(){if(current!==6||!activeMap||activeMap.getSource('leader-drone-heat'))return;const features=[...LowAltitudeGeoJSON.targets.features,...LowAltitudeGeoJSON.alerts.features].map((feature,index)=>({type:'Feature',geometry:feature.geometry,properties:{weight:index<4?.45:index<6?1:.72}}));activeMap.addSource('leader-drone-heat',{type:'geojson',data:{type:'FeatureCollection',features}});activeMap.addLayer({id:'leader-drone-heat',type:'heatmap',source:'leader-drone-heat',paint:{'heatmap-weight':['get','weight'],'heatmap-intensity':['interpolate',['linear'],['zoom'],10,.72,15,1.18],'heatmap-radius':['interpolate',['linear'],['zoom'],10,28,15,54],'heatmap-opacity':.48,'heatmap-color':['interpolate',['linear'],['heatmap-density'],0,'rgba(255,255,255,0)',.22,'rgba(245,227,161,.12)',.48,'rgba(228,181,47,.24)',.72,'rgba(227,74,74,.32)',1,'rgba(176,45,64,.44)']}})}

function monitoringTargetTracks(){const center=BusinessBackend.selected()?.center||LowAltitudeGeoJSON.center,records=monitoringTargetRecords();return{type:'FeatureCollection',features:records.map((record,index)=>{const target=record.feature,end=[...target.geometry.coordinates],dx=end[0]-center[0],dy=end[1]-center[1],start=[end[0]+dx*.72,end[1]+dy*.72],mid1=[end[0]+dx*.46-dy*.08,end[1]+dy*.46+dx*.08],mid2=[end[0]+dx*.2+dy*.05,end[1]+dy*.2-dx*.05],risk=droneRiskMeta(record),color={whitelist:'#f4f1f7',low:'#f5e3a1',medium:'#e4b52f',high:'#e34a4a'}[risk.tone];return{type:'Feature',properties:{target:target.properties.name,color,risk:risk.label,index},geometry:{type:'LineString',coordinates:[start,mid1,mid2,end]}}})}}

function monitoringTargetRecords(){const whitelist=LowAltitudeGeoJSON.targets.features.map((feature,index)=>({feature,index,type:feature.properties.kind?.includes('白名单')?'白名单无人机':'监测目标',status:feature.properties.status,alertIndex:null})),alerts=monitoringAlertRecords().map(record=>({feature:record.feature,index:whitelist.length+record.index,type:'告警目标',status:record.status,alertIndex:record.index,level:record.level}));return[...whitelist,...alerts]}

function playTargetTrajectory(record){if(record.alertIndex!==null){playAlertTrajectory(monitoringAlertRecords()[record.alertIndex]);return}if(!activeMap)return;const end=record.feature.geometry.coordinates,center=BusinessBackend.selected()?.center||LowAltitudeGeoJSON.center,dx=end[0]-center[0],dy=end[1]-center[1],start=[end[0]+dx*.72,end[1]+dy*.72],mid=[end[0]+dx*.36-dy*.08,end[1]+dy*.36+dx*.08],data={type:'Feature',properties:{},geometry:{type:'LineString',coordinates:[start,mid,end]}};if(activeMap.getSource('selected-target-track'))activeMap.getSource('selected-target-track').setData(data);else{activeMap.addSource('selected-target-track',{type:'geojson',data});activeMap.addLayer({id:'selected-target-track-line',type:'line',source:'selected-target-track',paint:{'line-color':'#b79be0','line-width':5,'line-opacity':1}})}activeMap.fitBounds(new mapboxgl.LngLatBounds(start,end),{padding:170,maxZoom:15,duration:700});toast(`正在回放 ${record.feature.properties.name} 的最近轨迹`)}

function showMonitoringTarget(index){const record=monitoringTargetRecords()[index];if(!record||!activeMap)return;if(record.alertIndex!==null){showMonitoringAlert(record.alertIndex);return}const feature=record.feature,coordinates=feature.geometry.coordinates;activeMap.flyTo({center:coordinates,zoom:15,pitch:30,duration:650});document.querySelectorAll('[data-unified-target]').forEach(item=>item.classList.toggle('active',+item.dataset.unifiedTarget===index));const popup=new mapboxgl.Popup({offset:18,closeOnClick:false,className:'monitor-alert-popup monitor-target-popup'}).setLngLat(coordinates).setHTML(`<div class="floating-alert-detail"><div class="floating-alert-head"><span class="status ${record.type==='白名单无人机'?'ok':'info'}">${record.type}</span><b>${feature.properties.name}</b></div><dl><dt>目标状态</dt><dd>${record.status}</dd><dt>目标类型</dt><dd>${feature.properties.kind}</dd><dt>当前位置</dt><dd>${coordinates[1].toFixed(5)}°N, ${coordinates[0].toFixed(5)}°E</dd><dt>飞行参数</dt><dd>${feature.properties.altitude||'--'}｜${feature.properties.speed||'--'}</dd></dl><div class="floating-alert-actions single"><button class="primary" data-target-track>轨迹回放</button></div></div>`).addTo(activeMap);popup.getElement().querySelector('[data-target-track]').onclick=()=>playTargetTrajectory(record)}

function enhanceUnifiedMonitoringTargets(){if(current!==4)return;const pane=q('.monitor-pane[data-pane="targets"]'),list=pane?.querySelector('.target-list');if(!list)return;const records=monitoringTargetRecords();list.innerHTML=records.map(record=>{const risk=droneRiskMeta(record);return`<div class="list-item" data-unified-target="${record.index}"><div class="row"><strong><i class="drone-list-icon drone-${risk.tone}" aria-hidden="true"></i>${record.feature.properties.name}</strong><span class="status ${record.type==='白名单无人机'?'ok':record.alertIndex!==null?'danger':'info'}">${record.status}</span></div><span class="muted">${risk.label}｜${record.type}${record.feature.properties.altitude?`｜高度 ${record.feature.properties.altitude}｜${record.feature.properties.speed}`:''}</span></div>`}).join('');pane.querySelector('.panel-title')?.remove();pane.querySelector('.table-wrap')?.remove();list.querySelectorAll('[data-unified-target]').forEach(item=>item.onclick=()=>showMonitoringTarget(+item.dataset.unifiedTarget));const tab=q('.monitor-tabs [data-tab="targets"]');if(tab)tab.innerHTML=`目标列表 <em>${records.length}</em>`;q('.alert-queue')?.querySelectorAll('[data-alert]').forEach(item=>{const level=item.dataset.level,risk=droneRiskMeta({level}),strong=item.querySelector('strong');if(strong&&!strong.querySelector('.drone-list-icon'))strong.insertAdjacentHTML('afterbegin',`<i class="drone-list-icon drone-${risk.tone}" aria-hidden="true"></i>`)})}

function openRecommendedDisposal(record){const target=record.feature.geometry.coordinates,vehicles=perimeterResources('车辆').map(feature=>({feature,distance:distanceKm(target,feature.geometry.coordinates)})).sort((a,b)=>a.distance-b.distance),speaker=vehicles[0],checker=vehicles[1]||vehicles[0],eta=item=>Math.max(1,Math.ceil(item.distance/32*60));openModal('机动巡逻处置方案',`<div class="disposal-recommend"><div class="disposal-summary"><span class="status ${record.level==='高危'?'danger':record.level==='中危'?'warn':'info'}">${record.level}</span><div><b>${record.feature.properties.name}</b><small>${record.code}｜${record.feature.properties.riskZone||record.status}</small></div></div><div class="patrol-advantage"><b>就近巡逻力量</b><span>系统已按车辆位置、任务状态和预计到达时间自动匹配</span></div><label class="patrol-action"><input type="checkbox" checked><span><b>通知 ${speaker.feature.properties.name.split('｜')[0]} 喊话警示</b><small>${speaker.feature.properties.location}｜距目标 ${speaker.distance.toFixed(1)}km｜预计 ${eta(speaker)} 分钟进入喊话范围</small></span></label><label class="patrol-action"><input type="checkbox" checked><span><b>通知 ${checker.feature.properties.name.split('｜')[0]} 前往现场核查</b><small>${checker.feature.properties.location}｜距目标 ${checker.distance.toFixed(1)}km｜预计 ${eta(checker)} 分钟到达</small></span></label><label><input type="checkbox" checked> 侦测设备持续跟踪并锁定目标身份</label><label><input type="checkbox" ${record.level==='高危'?'checked':''}> 车载定向反制设备进入待命状态</label><label><input type="checkbox"> 联动属地公安与活动现场指挥组</label><div class="disposal-note"><b>处置建议</b><p>${record.level==='高危'?`优先由 ${speaker.feature.properties.name.split('｜')[0]} 实施喊话驱离，${checker.feature.properties.name.split('｜')[0]} 同步抵近核查；身份复核后再决定是否启动车载定向反制。`:`由就近巡逻车完成喊话和身份核查，固定设备保持连续跟踪。`}</p></div></div>`,()=>{record.feature.properties.status='处置中';toast(`${record.code} 已下发至 ${speaker.feature.properties.name.split('｜')[0]}、${checker.feature.properties.name.split('｜')[0]}`);render()});q('.modal-confirm').textContent='确认并下发巡逻任务'}

function playAlertTrajectory(record){if(!activeMap)return;const end=record.feature.geometry.coordinates,center=BusinessBackend.selected()?.center||LowAltitudeGeoJSON.center,start=[end[0]+(end[0]-center[0])*.7,end[1]+(end[1]-center[1])*.7],mid=[(start[0]+end[0])/2+.002,(start[1]+end[1])/2+.0015],data={type:'Feature',properties:{},geometry:{type:'LineString',coordinates:[start,mid,end]}};if(activeMap.getSource('alert-playback'))activeMap.getSource('alert-playback').setData(data);else{activeMap.addSource('alert-playback',{type:'geojson',data});activeMap.addLayer({id:'alert-playback-line',type:'line',source:'alert-playback',paint:{'line-color':'#3d8ff0','line-width':4,'line-opacity':.9,'line-dasharray':[2,1]}})}activeMap.fitBounds(new mapboxgl.LngLatBounds(start,end),{padding:170,maxZoom:15,duration:700});toast('已加载该告警目标最近5分钟轨迹')}

function showMonitoringAlert(index){const record=monitoringAlertRecords()[index];if(!record||!activeMap)return;const coordinates=record.feature.geometry.coordinates;activeMap.flyTo({center:coordinates,zoom:15.2,pitch:36,duration:650});document.querySelectorAll('[data-alert]').forEach(item=>item.classList.toggle('active',+item.dataset.alert===index));const popup=new mapboxgl.Popup({offset:18,closeOnClick:false,className:'monitor-alert-popup'}).setLngLat(coordinates).setHTML(`<div class="floating-alert-detail"><div class="floating-alert-head"><span class="status ${record.level==='高危'?'danger':record.level==='中危'?'warn':'info'}">${record.level}</span><b>${record.feature.properties.name}</b></div><dl><dt>告警编号</dt><dd>${record.code}</dd><dt>当前状态</dt><dd>${record.status}</dd><dt>发生时间</dt><dd>${record.time}</dd><dt>坐标位置</dt><dd>${coordinates[1].toFixed(5)}°N, ${coordinates[0].toFixed(5)}°E</dd></dl><div class="floating-alert-actions"><button data-alert-track>轨迹回放</button><button class="primary" data-alert-dispose>实施处置</button></div></div>`).addTo(activeMap);const node=popup.getElement();node.querySelector('[data-alert-track]').onclick=()=>playAlertTrajectory(record);node.querySelector('[data-alert-dispose]').onclick=()=>openRecommendedDisposal(record)}

function restructureMonitoringV2(){if(current!==4)return;const layout=q('.l5'),side=layout?.querySelector('.side'),metrics=layout?.querySelector('.metrics'),map=layout?.querySelector('.real-map'),history=layout?.querySelector('.bottom'),timeline=layout?.querySelector('.timeline');if(!side||!map)return;history?.remove();timeline?.remove();layout.classList.add('monitor-tabs-layout','monitor-merged');const records=monitoringAlertRecords(),targets=LowAltitudeGeoJSON.targets.features;side.innerHTML=`<div class="monitor-tabs"><button data-tab="targets">目标列表</button><button data-tab="alerts" class="active">告警信息 <em>${records.length}</em></button></div><div class="monitor-pane" data-pane="targets"><div class="list target-list">${targets.map((feature,index)=>`<div class="list-item" data-target="${index}"><div class="row"><strong>${feature.properties.name}</strong><span class="status ${feature.properties.kind==='异常目标'?'danger':'ok'}">${feature.properties.status}</span></div><span class="muted">${feature.properties.kind}${feature.properties.altitude?`｜高度 ${feature.properties.altitude}｜${feature.properties.speed}`:''}</span></div>`).join('')}</div><div class="panel-title">轨迹回放记录</div><div class="table-wrap"><table><tbody>${rows(3)}</tbody></table></div></div><div class="monitor-pane active" data-pane="alerts"><div class="monitor-alert-filters"><select data-alert-level><option value="">全部等级</option><option>高危</option><option>中危</option><option>低危</option></select><select data-alert-status><option value="">全部状态</option>${[...new Set(records.map(record=>record.status))].map(status=>`<option>${status}</option>`).join('')}</select></div><div class="list alert-queue">${records.map(record=>`<div class="list-item" data-alert="${record.index}" data-level="${record.level}" data-status="${record.status}"><div class="row"><strong><span class="status ${record.level==='高危'?'danger':record.level==='中危'?'warn':'info'}">${record.level}</span> ${record.feature.properties.name}</strong><small>${record.time}</small></div><span class="muted">${record.status}｜点击定位并查看详情</span></div>`).join('')}</div></div>`;metrics?.classList.add('monitor-map-metrics');side.classList.add('monitor-map-side');if(metrics)map.appendChild(metrics);map.appendChild(side);side.querySelectorAll('[data-tab]').forEach(button=>button.onclick=()=>{side.querySelectorAll('[data-tab],.monitor-pane').forEach(item=>item.classList.remove('active'));button.classList.add('active');side.querySelector(`[data-pane="${button.dataset.tab}"]`).classList.add('active')});const filter=()=>{const level=side.querySelector('[data-alert-level]').value,status=side.querySelector('[data-alert-status]').value;side.querySelectorAll('[data-alert]').forEach(item=>item.hidden=!!((level&&item.dataset.level!==level)||(status&&item.dataset.status!==status)))};side.querySelectorAll('.monitor-alert-filters select').forEach(select=>select.onchange=filter);side.querySelectorAll('[data-alert]').forEach(item=>item.onclick=()=>showMonitoringAlert(+item.dataset.alert));side.querySelectorAll('[data-target]').forEach(item=>item.onclick=()=>{const feature=targets[+item.dataset.target];activeMap?.flyTo({center:feature.geometry.coordinates,zoom:15});new mapboxgl.Popup({offset:12}).setLngLat(feature.geometry.coordinates).setHTML(`<b>${feature.properties.name}</b><br>${feature.properties.kind} · ${feature.properties.status}`).addTo(activeMap)})}

