function heatPointsToGrid(data){
  const activity=BusinessBackend.selected(),outer=Math.max(...(activity?.levels||[{radius:3000}]).map(level=>level.radius)),half=outer/12*.44;
  return {type:'FeatureCollection',features:data.features.map(feature=>{const c=feature.geometry.coordinates,sw=offsetFromCenter(c,-half,-half),se=offsetFromCenter(c,half,-half),ne=offsetFromCenter(c,half,half),nw=offsetFromCenter(c,-half,half);return {type:'Feature',properties:{...feature.properties},geometry:{type:'Polygon',coordinates:[[sw,se,ne,nw,sw]]}}})};
}

