function bindNotificationCenter(){
  const bell=q('.bell');if(!bell)return;
  bell.onclick=event=>{event.stopPropagation();const center=q('.notification-center');if(!center)return;center.classList.toggle('open');if(center.classList.contains('open'))setTimeout(()=>document.addEventListener('click',outside=>{if(!outside.target.closest('.notification-center'))center.classList.remove('open')},{once:true}),0)};
}

function auditPageCleanup(){
  if(current===6){
    const hero=q('.leader-hero'),mapPanel=q('.leader-map'),kpis=q('.leader-kpis'),decisions=q('.leader-decisions');
    if(hero&&mapPanel)mapPanel.prepend(hero);
    if(kpis&&mapPanel){kpis.querySelector('article:last-child')?.remove();hero.after(kpis)}
    if(decisions){updateDecisionNotification(decisions);decisions.remove()}
  }
  if(current===5){q('.l6 .bottom')?.remove();q('.l6')?.classList.add('no-process-bottom')}
}

function mapFeaturesForPage(){
  const d=window.LowAltitudeGeoJSON,custom=storedDevices(),simDevices=perimeterResources('设备'),simVehicles=perimeterResources('车辆');
  const mobilityPoints=simVehicles.map((feature,index)=>{const copy=JSON.parse(JSON.stringify(feature));if(index>=3){copy.properties.name='';copy.properties.color='#9d91a6'}return copy});
  const sets=[[d.devices.features[0]],[...simDevices,...custom],mobilityPoints,[...d.devices.features.slice(0,4)],[...d.targets.features,...simDevices,...custom,...d.alerts.features],[...d.alerts.features],[...d.targets.features,...d.alerts.features,...simVehicles.slice(0,3)]];
  return {type:'FeatureCollection',features:sets[current]||[]};
}

