// The analysis tabs are created after Mapbox finishes loading. Event delegation keeps
// the compliance guardrail available even on a slow network or after a style switch.
document.addEventListener('click',event=>{
  const counterTab=event.target.closest('.coverage-analysis-tabs [data-mode="counter"]');
  if(!counterTab)return;
  setTimeout(()=>{
    const metrics=q('.l2 .cardgrid');
    if(!metrics||metrics.querySelector('.compliance-card'))return;
    const card=document.createElement('div');
    card.className='compliance-card';
    card.innerHTML='<b>反制合规约束</b><span>授权频段：GNSS L1/L2、2.4GHz、5.8GHz</span><span>适用对象：确认违规且完成身份核验的无人机</span><small>启用反制前必须完成授权审批，避免影响公安、媒体等白名单飞行。</small>';
    metrics.appendChild(card);
  },0);
});
function render(){if(current===3)current=7;if(current===5)current=4;if(ui.timer)clearInterval(ui.timer);if(activeMap){activeMap.remove();activeMap=null}mapImagery=false;document.body.classList.toggle('monitor-mode',current===4);document.body.classList.toggle('leader-mode',current===6);document.body.classList.toggle('utility-mode',current>=7);shellV2();q('#workspace').innerHTML=[page1,page2,page3,page4,page5,page6,pageLeadership,pageDeviceManagement,pageAnalytics][current]();bindInteractions()}window.addEventListener('hashchange',()=>{let n=+(location.hash.slice(1)||1)-1;if(n===3)n=7;if(n===5)n=4;if(n!==current){current=n;render()}});render();

/* Detailed target intelligence and compact mobility decision panel. */
function monitoringDroneProfile(feature,index,authorized=false){const models=authorized?['DJI Matrice 350 RTK','DJI Mavic 3E','Autel EVO Max 4T']:['DJI Air 3','DJI Mavic 3 Pro','型号待识别'],types=['四旋翼无人机','多旋翼无人机','行业级无人机'];return{started:feature.properties.startTime||`14:${String(18-index%7).padStart(2,'0')}:${String(26+index*3).slice(-2)}`,type:feature.properties.droneType||types[index%types.length],model:feature.properties.model||models[index%models.length],identity:feature.properties.identity||feature.properties.remoteId||(authorized?`RID-ZJ-${String(26011801+index)}`:'未识别'),method:feature.properties.identifyMethod||(authorized?'Remote ID + 光电识别':'雷达 / 频谱融合识别')}}
function monitoringDetailMarkup(record,feature,index,authorized){const coordinates=feature.geometry.coordinates,profile=monitoringDroneProfile(feature,index,authorized);return`<dl class="target-detail-grid"><dt>开始时间</dt><dd>${record.time||profile.started}</dd><dt>无人机类型</dt><dd>${profile.type}</dd><dt>品牌型号</dt><dd>${profile.model}</dd><dt>身份标识</dt><dd>${profile.identity}</dd><dt>识别方式</dt><dd>${profile.method}</dd><dt>当前状态</dt><dd>${record.status}</dd><dt>当前位置</dt><dd>${coordinates[1].toFixed(5)}°N, ${coordinates[0].toFixed(5)}°E</dd><dt>高度 / 速度</dt><dd>${feature.properties.altitude||'--'} / ${feature.properties.speed||'--'}</dd></dl>`}
function showMonitoringTarget(index){const record=monitoringTargetRecords()[index];if(!record||!activeMap)return;if(record.alertIndex!==null){showMonitoringAlert(record.alertIndex);return}const feature=record.feature,coordinates=feature.geometry.coordinates;activeMap.flyTo({center:coordinates,zoom:15,pitch:30,duration:650});document.querySelectorAll('[data-unified-target]').forEach(item=>item.classList.toggle('active',+item.dataset.unifiedTarget===index));const popup=new mapboxgl.Popup({offset:18,closeOnClick:false,className:'monitor-alert-popup monitor-target-popup'}).setLngLat(coordinates).setHTML(`<div class="floating-alert-detail"><div class="floating-alert-head"><span class="status ok">${record.type}</span><b>${feature.properties.name}</b></div>${monitoringDetailMarkup(record,feature,index,true)}<div class="floating-alert-actions single"><button class="primary" data-target-track>轨迹回放</button></div></div>`).addTo(activeMap);popup.getElement().querySelector('[data-target-track]').onclick=()=>playTargetTrajectory(record)}
function showMonitoringAlert(index){const record=monitoringAlertRecords()[index];if(!record||!activeMap)return;const feature=record.feature,coordinates=feature.geometry.coordinates;activeMap.flyTo({center:coordinates,zoom:15.2,pitch:36,duration:650});document.querySelectorAll('[data-alert]').forEach(item=>item.classList.toggle('active',+item.dataset.alert===index));const popup=new mapboxgl.Popup({offset:18,closeOnClick:false,className:'monitor-alert-popup'}).setLngLat(coordinates).setHTML(`<div class="floating-alert-detail"><div class="floating-alert-head"><span class="status ${record.level==='高危'?'danger':record.level==='中危'?'warn':'info'}">${record.level}</span><b>${feature.properties.name}</b></div>${monitoringDetailMarkup(record,feature,index,false)}<div class="floating-alert-actions"><button data-alert-track>轨迹回放</button><button class="primary" data-alert-dispose>实施处置</button></div></div>`).addTo(activeMap);const node=popup.getElement();node.querySelector('[data-alert-track]').onclick=()=>playAlertTrajectory(record);node.querySelector('[data-alert-dispose]').onclick=()=>openRecommendedDisposal(record)}
function finalizeMobilityWorkspace(){if(current!==2)return;q('.mobility-tasks')?.remove();q('.settings-trigger')?.remove();const map=q('.mobility-page .real-map');if(!map)return;const weakAreas=coverageWeakAreas(),vehicles=perimeterResources('车辆'),modes=['定向反制','雷达补盲','无线电侦测'];const dock=document.createElement('aside');dock.className='mobility-command-dock';dock.innerHTML=`<header><div><b>补盲方案与资源分配</b><small>方案、车辆与覆盖复评同步更新</small></div><span class="status ok">实时推演</span></header><div class="mobility-plan-switch"><button data-plan="economy">少占资源</button><button class="active recommended-plan" data-plan="balanced">推荐方案</button><button data-plan="strong">最高保障</button></div><div class="mobility-dock-body"><section class="post-mobility-review mobility-brief"><div class="mobility-brief-head"><span><b>推荐部署 3 辆</b><small>自动匹配覆盖评估薄弱区</small></span><strong data-after-score>92</strong></div><div class="mobility-brief-metrics"><span><small>覆盖率</small><b>78% → <em data-after-coverage>94%</em></b></span><span><small>剩余盲区</small><b data-after-blind>0.28 km²</b></span></div><div class="mobility-brief-links">${weakAreas.map((area,index)=>`<p><span><i></i><b>${area.name}</b></span><em>${vehicles[index]?.properties.name.split('｜')[0]||`保障车${index+1}`} · ${modes[index]}</em></p>`).join('')}</div><div class="review-verdict ok">复评达标，可下发部署</div></section></div><footer><button class="ghost" data-focus-routes>查看调度路线</button><button class="primary" data-apply-plan>确认并下发</button></footer>`;map.appendChild(dock);dock.querySelectorAll('[data-plan]').forEach(button=>button.onclick=()=>previewMobilityPlan(button.dataset.plan));dock.querySelector('[data-focus-routes]').onclick=()=>activeMap?.easeTo({center:BusinessBackend.selected()?.center||LowAltitudeGeoJSON.center,zoom:13.35,pitch:42,bearing:-12,duration:650});dock.querySelector('[data-apply-plan]').onclick=applyMobilityPlan;previewMobilityPlan(mobilityPlanKey,true)}
